SELECT A.NFCLT_CMD_MST_SEQ -- 장비 명령어 MST SEQ , A.SFCLT_TYPE -- 장비 타입 , A.SFCLT_CMD -- 장비실행 명령어 , A.NPRIORITY -- 장비실행 명령어 순서 , A.SUSE_YN -- 사용여부 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , A.RNUM FROM ( SELECT A.NFCLT_CMD_MST_SEQ -- 장비 명령어 MST SEQ , A.SFCLT_TYPE -- 장비 타입 , A.SFCLT_CMD -- 장비실행 명령어 , A.NPRIORITY -- 장비실행 명령어 순서 , A.SUSE_YN -- 사용여부 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , ROWNUM RNUM FROM ( SELECT A.NFCLT_CMD_MST_SEQ -- 장비 명령어 MST SEQ , A.SFCLT_TYPE -- 장비 타입 , A.SFCLT_CMD -- 장비실행 명령어 , A.NPRIORITY -- 장비실행 명령어 순서 , A.SUSE_YN -- 사용여부 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID FROM MST.TB_INTGRM_FCLT_CMD_MST A -- 장비별 명령어 MST WHERE 1=1
AND A.SFCLT_TYPE = #{sfcltType, jdbcType=VARCHAR}
AND A.SFCLT_CMD ILIKE '%' || #{searchWrd, jdbcType=VARCHAR} || '%'
AND A.SUSE_YN = #{suseYn, jdbcType=CHAR}
ORDER BY A.SFCLT_TYPE , A.NPRIORITY ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT count(1) totalCount 
FROM MST.TB_INTGRM_FCLT_CMD_MST A	 -- 장비별 명령어 MST 
WHERE 1=1 

		AND A.SFCLT_TYPE = #{sfcltType, jdbcType=VARCHAR}


		AND A.SFCLT_CMD ILIKE '%' || #{searchWrd, jdbcType=VARCHAR} || '%'


		AND A.SUSE_YN = #{suseYn, jdbcType=CHAR}

SELECT A.NFCLT_CMD_MST_SEQ -- 장비 명령어 MST SEQ , A.SFCLT_TYPE -- 장비 타입 , A.SFCLT_CMD -- 장비실행 명령어 , A.NPRIORITY -- 장비실행 명령어 순서 , A.SUSE_YN -- 사용여부 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID FROM MST.TB_INTGRM_FCLT_CMD_MST A -- 장비별 명령어 MST WHERE 1=1
AND A.SFCLT_TYPE = #{sfcltType, jdbcType=VARCHAR}
ORDER BY A.SFCLT_TYPE, A.NPRIORITY

