	SFCLT_TYPE		-- 장비 타입
	,	SFCLT_CMD		-- 장비실행 명령어
	,	NPRIORITY		-- 장비실행 명령어 순서
	,   SUSE_YN		-- 사용여부
	,	SCREATE_ID
	,	SMODIFY_ID

) VALUES (
	#{sfcltType, jdbcType=VARCHAR}
	,	#{sfcltCmd, jdbcType=VARCHAR}
	,	#{npriority, jdbcType=INTEGER}
	,	#{suseYn, jdbcType=CHAR}
	,	#{screateId, jdbcType=VARCHAR}
	,	#{smodifyId, jdbcType=VARCHAR}
)

