UPDATE
	MST.TB_INTGRM_FCLT_CMD_MST A
SET

		A.SFCLT_TYPE = #{sfcltType, jdbcType=VARCHAR}


		, A.SFCLT_CMD = #{sfcltCmd, jdbcType=VARCHAR}


		, A.NPRIORITY = #{npriority, jdbcType=INTEGER}


		, A.SUSE_YN = #{suseYn, jdbcType=CHAR}


		, A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}

		, A.DMODIFY_DT = SYSDATE
WHERE 1=1
	AND A.NFCLT_CMD_MST_SEQ = #{nfcltCmdMstSeq, jdbcType=BIGINT}
